const calls = Array.isArray($json) ? $json : [];
const now = Date.now();

// Yesterday 18:00 → today 08:00 window
const todayDate = new Date();
const cutoffEnd = new Date(todayDate.getFullYear(), todayDate.getMonth(), todayDate.getDate(), 8, 0, 0).getTime();
const cutoffStart = cutoffEnd - 14 * 3600_000; // 14 hours back = yesterday 18:00

const overnightCalls = calls.filter(c => {
  const ts = c.start_timestamp ?? 0;
  return ts >= cutoffStart && ts < cutoffEnd;
});

const voicemails = overnightCalls.filter(c => c.call_analysis?.in_voicemail === true);
const missed = overnightCalls.filter(c => c.call_status === 'error' || c.disconnection_reason === 'dial_no_answer');
const booked = overnightCalls.filter(c => {
  const summary = (c.call_analysis?.call_summary ?? '').toLowerCase();
  return summary.includes('book') || c.call_analysis?.custom_analysis_data?.outcome === 'booked';
});

// Format date for digest header
const dateStr = new Date(cutoffStart).toLocaleDateString('en-GB', {
  weekday: 'long', day: 'numeric', month: 'long'
});

// Build digest lines
const lines = [];
lines.push(`📋 Ava Overnight Summary — ${dateStr}`);
lines.push('');
lines.push(`Calls received after 18:00: ${overnightCalls.length}`);
lines.push(`  • Booked: ${booked.length}`);
lines.push(`  • Voicemails: ${voicemails.length}`);
lines.push(`  • Missed/disconnected: ${missed.length}`);
lines.push('');

if (voicemails.length > 0) {
  lines.push('VOICEMAILS — need callback:');
  for (const vm of voicemails) {
    const time = vm.start_timestamp 
      ? new Date(vm.start_timestamp).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' })
      : '?';
    const transcript = vm.transcript ?? vm.call_analysis?.call_summary ?? 'No transcript';
    lines.push(`  ${time} — ${vm.from_number ?? 'Unknown'} — ${transcript.substring(0, 120)}...`);
  }
  lines.push('');
}

if (missed.length > 0) {
  lines.push('MISSED CALLS — consider outbound follow-up:');
  for (const mc of missed) {
    const time = mc.start_timestamp
      ? new Date(mc.start_timestamp).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' })
      : '?';
    lines.push(`  ${time} — ${mc.from_number ?? 'Unknown'}`);
  }
  lines.push('');
}

if (booked.length > 0) {
  lines.push(`BOOKINGS TAKEN (${booked.length}):`);
  for (const bk of booked) {
    const summary = bk.call_analysis?.call_summary ?? '';
    lines.push(`  • ${summary.substring(0, 100)}`);
  }
  lines.push('');
}

const actionsNeeded = voicemails.length + missed.length;
if (actionsNeeded > 0) {
  lines.push(`Action required: ${voicemails.length > 0 ? `${voicemails.length} voicemail callback${voicemails.length !== 1 ? 's' : ''}` : ''}${voicemails.length > 0 && missed.length > 0 ? ', ' : ''}${missed.length > 0 ? `${missed.length} missed call follow-up${missed.length !== 1 ? 's' : ''}` : ''}`);
} else {
  lines.push('No actions required — clean overnight.');
}

lines.push('');
lines.push('— Ava, StrydeOS');

return [{
  digestText: lines.join('\n'),
  digestHtml: '<pre style="font-family:monospace;font-size:13px;line-height:1.6;">' + lines.join('\n') + '</pre>',
  actionsNeeded,
  voicemailCount: voicemails.length,
  totalOvernightCalls: overnightCalls.length,
  dateStr,
}];

